import { BarChart } from '@mui/x-charts/BarChart';

export default function Crypto() {
  return (
    <BarChart
      xAxis={[
        {
          data: ['A', 'B', 'C'],
          scaleType: 'band',
        },
      ]}
      series={[
        {
          data: [10, 20, 30],
          label: 'Значения',
        },
      ]}
      width={500}
      height={300}
    />
  );
}
